"use client";
import Image from "next/image";
import { lostItems } from "@/app/data/lostitem";
import { foundItems } from "@/app/data/founditem";
import React from "react";
import { Tag, MapPin, Calendar, Clock, Info } from "lucide-react";

const ItemDetails = ({ params }) => {
  const { id } = React.use(params);
  console.log("hello");
  console.log(id);

  const item =
    lostItems.find((it) => it.id == id) ||
    foundItems.find((it) => it.id == id);

  if (!item) return <div className="p-10 text-center">Item not found.</div>;

  return (
    <div className="max-w-4xl min-h-[90vh] mx-auto p-6 space-y-6">

      <h1 className="text-3xl md:text-4xl font-bold text-gray-900">
        {item.title}
      </h1>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">

        {/* Image */}
        <div className="w-full flex justify-center">
          <img
            src={item.image}
            width={500}
            height={500}
            alt={item.title}
            className="rounded-xl shadow-lg border object-cover"
          />
        </div>

        {/* Details */}
        <div className="space-y-5">

          {/* Status */}
          <div
            className={`text-center py-2 rounded-xl font-bold text-lg shadow ${
              item.status === "lost"
                ? "bg-red-100 text-red-700"
                : "bg-green-100 text-green-700"
            }`}
          >
            STATUS: {item.status.toUpperCase()}
          </div>

          {/* Info Card */}
          <div className="bg-gray-50 p-5 rounded-xl border border-gray-200 space-y-4 shadow-sm">
            <h3 className="text-xl font-semibold flex items-center text-gray-800">
              <Info className="w-5 h-5 mr-2 text-indigo-600" />
              Item Information
            </h3>

            <p className="text-gray-600">{item.description}</p>

            <div className="space-y-3 text-sm text-gray-700">
              <p className="flex items-center">
                <Tag className="w-4 h-4 mr-2 text-indigo-500" />
                <strong className="mr-1">Category:</strong> {item.category}
              </p>

              <p className="flex items-center">
                <MapPin className="w-4 h-4 mr-2 text-indigo-500" />
                <strong className="mr-1">Last Seen / Found Location:</strong>{" "}
                {item.location}
              </p>

              <p className="flex items-center">
                <Calendar className="w-4 h-4 mr-2 text-indigo-500" />
                <strong className="mr-1">Approx. Date:</strong> {item.date}
              </p>

              <p className="flex items-center">
                <Clock className="w-4 h-4 mr-2 text-indigo-500" />
                <strong className="mr-1">Reported On:</strong>{" "}
                {item.reportedDate || "N/A"}
              </p>
            </div>
          </div>

          {/* ✅ Claim Item Button */}
          <button
            className="
              w-full 
              py-3 
              bg-indigo-600 
              text-white 
              rounded-xl 
              font-semibold 
              text-lg 
              shadow-md 
              hover:bg-indigo-700 
              transition
            "
          >
            Claim This Item
          </button>

        </div>
      </div>

    </div>
  );
};

export default ItemDetails;
